matlabbatch{1}.spm.spatial.coreg.estimate.eoptions.cost_fun = 'nmi';
% Registration involves finding parameters that either maximise or minimise some objective func-
% tion. For inter-modal registration, use Mutual Information [19, 85], Normalised Mutual Infor-
% mation [81], or Entropy Correlation Coefficient [61].For within modality, you could also use Nor-
% malised Cross Correlation.
matlabbatch{1}.spm.spatial.coreg.estimate.eoptions.sep = [4 2]; % The average distance between sampled points (in mm). Can be a vector to allow a coarse regis-
% tration followed by increasingly fine ones.
matlabbatch{1}.spm.spatial.coreg.estimate.eoptions.tol = [0.02 0.02 0.02 0.001 0.001 0.001 0.01 0.01 0.01 0.001 0.001 0.001]; %The accuracy for each parameter. Iterations stop when differences between successive estimates
% are less than the required tolerance.
matlabbatch{1}.spm.spatial.coreg.estimate.eoptions.fwhm = [7 7];
% Gaussian smoothing to apply to the 256x256 joint histogram. Other information theoretic coreg-
% istration methods use fewer bins, but Gaussian smoothing seems to be more elegant.
